function JobProgress(t,e){{var n=this;$("#"+t)}this.tabID=t,this.updateAutoNumberRow=function(){var t=1;$(".transaction-detail-row").each(function(){var e=$(this).find("input[name='numberDetail[]']");e.length&&(e.each(function(){$(this).val(t).trigger("change")}),t++)})},this.afterRemoveRowHandler=function(){n.updateAutoNumberRow()},this.rebindEl=function(){n.updateAutoNumberRow()},this.loadOnReady=function(){e.detail&&0!=e.detail.length||addNewTemplateRow("detail-row-template",null,null,n.rebindEl),n.rebindEl()}}